def test_payroll_run_atomic_rollback_on_forced_failure(
    hr_admin_client, seed_active_employees, current_month_period, unique_idem_key, fault_injection_flag
):
    resp = hr_admin_client.post(
        "/api/payroll-runs",
        json={"period": current_month_period},
        headers={
            "Idempotency-Key": unique_idem_key,
            "X-Force-Failure": fault_injection_flag,
        },
    )
    assert resp.status_code in (202, 500, 201)
    run_id = resp.json().get("id") or resp.json().get("run_id")
    assert run_id is not None

    run = wait_for_terminal_state(
        hr_admin_client, f"/api/payroll-runs/{run_id}", timeout=10
    )
    assert run["state"] == "failed"

    stubs_resp = hr_admin_client.get(f"/api/payroll-runs/{run_id}/pay-stubs")
    assert stubs_resp.status_code == 200
    assert len(stubs_resp.json()["items"]) == 0

    audit_resp = hr_admin_client.get(
        "/api/audit-log", params={"entity": "payroll-run", "entity_id": run_id}
    )
    assert any(
        "fail" in e.get("event", "").lower() for e in audit_resp.json()["items"]
    )

FIXED_IDEM_KEY = "idem-key-r-web-073-retry-test"

def test_payroll_run_idempotent_on_retry_with_same_key(
    hr_admin_client, seed_active_employees, current_month_period, cleanup_payroll_run
):
    payload = {"period": current_month_period}
    headers = {"Idempotency-Key": FIXED_IDEM_KEY}

    first = hr_admin_client.post("/api/payroll-runs", json=payload, headers=headers)
    assert first.status_code in (200, 201)
    run_id = first.json()["id"]
    wait_for_state(hr_admin_client, f"/api/payroll-runs/{run_id}", "completed", timeout=10)

    retry = hr_admin_client.post("/api/payroll-runs", json=payload, headers=headers)
    assert retry.status_code in (200, 201)
    assert retry.json()["id"] == run_id

    stubs = hr_admin_client.get(f"/api/payroll-runs/{run_id}/pay-stubs").json()["items"]
    assert len(stubs) == len(seed_active_employees)

    audit_items = hr_admin_client.get(
        "/api/audit-log", params={"entity": "payroll-run", "entity_id": run_id}
    ).json()["items"]
    completed_events = [e for e in audit_items if "completed" in e.get("event", "").lower()]
    assert len(completed_events) == 1
